import express from "express";
import cors from "cors";
import cookieParser from "cookie-parser";
import { corsOptions } from "./corsOptions.js";
import {
  csrfProtectionMiddleware,
  csrfTokenProvider,
  csrfErrorHandler,
} from "../middleware/csrfProtection.js";
import { globalLimiter } from "../middleware/rateLimiter.js";
import errorHandler from "../middleware/errorHandler.js";

// Import webhook routes that bypass CSRF
import webhookRoutes from "../routes/webhookRoutes.js";
import slackRoutes from "../routes/slackRoutes.js";
import { slackWebhookParser } from "../middleware/slackWebhookParser.js";

export function configureExpress(app) {
  // Trust proxy for Render/Vercel
  app.set("trust proxy", 1);

  // MIDDLEWARES
  app.use(cors(corsOptions));

  app.use(express.json({ limit: "50mb" }));
  app.use(express.urlencoded({ extended: true, limit: "50mb" }));

  // ==========================================
  // 1. BYPASSED ROUTES (No CSRF Protection)
  //    External services authenticate via their own mechanisms.
  // ==========================================
  app.use("/api/slack", slackWebhookParser, slackRoutes);
  app.use("/api/webhooks", webhookRoutes);

  // ==========================================
  // 2. COOKIES & CSRF (Global for all remaining routes)
  // ==========================================
  app.use(cookieParser());
  app.use(csrfProtectionMiddleware);

  // CSRF token provider
  app.get("/api/csrf-token", (req, res) => {
    res.json({ csrfToken: req.csrfToken() });
  });

  // Health check endpoint — registered BEFORE the global rate limiter so
  // keep-alive pings (e.g. from GitHub Actions cron job) are never blocked.
  app.get(["/health", "/api/health"], (req, res) => {
    res.status(200).json({
      status: "UP",
      timestamp: new Date().toISOString(),
      env: process.env.NODE_ENV,
    });
  });

  // GLOBAL RATE LIMITER
  app.use(globalLimiter);
}

export function configureErrorHandling(app) {
  // CSRF ERROR HANDLER
  app.use(csrfErrorHandler);
  // ERROR HANDLER
  app.use(errorHandler);
}

import AuditLog from "../models/auditLogModel.js";
import AuditLogExport from "../models/auditLogExportModel.js";
import { dataExportQueue } from "../services/queueService.js";
import {
  AUDIT_EXPORT_DIRECTORY,
  buildAuditLogFilter,
  streamCsvExport,
  streamXlsxExport,
} from "../services/auditLogExportService.js";
import { sendSuccess, sendError } from "../utils/responseHandler.js";
import fs from "fs";
import path from "path";

const LARGE_EXPORT_THRESHOLD = 10000;
const EXPORT_TTL_MS = 24 * 60 * 60 * 1000;

const parseFilters = (query, organizationId) => {
  const { action, startDate, endDate } = query;
  if (startDate && Number.isNaN(new Date(startDate).getTime())) {
    throw new Error("Invalid startDate.");
  }
  if (endDate && Number.isNaN(new Date(endDate).getTime())) {
    throw new Error("Invalid endDate.");
  }
  return buildAuditLogFilter({ organizationId, action, startDate, endDate });
};

/**
 * ✅ Get Audit Logs for an Organization (Admin/Owner only)
 * GET /api/organization/:id/audit-logs
 */
export const getOrganizationAuditLogs = async (req, res) => {
  try {
    const organizationId = req.params.id;
    const { format, page = 1, limit = 20 } = req.query;
    if (format && !["csv", "xlsx"].includes(format)) {
      return sendError(res, 400, "Export format must be csv or xlsx.");
    }

    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);
    if (!Number.isInteger(pageNum) || pageNum < 1 || !Number.isInteger(limitNum) || limitNum < 1) {
      return sendError(res, 400, "page and limit must be positive integers.");
    }
    const skip = (pageNum - 1) * limitNum;
    const filter = parseFilters(req.query, organizationId);

    if (format) {
      const total = await AuditLog.countDocuments(filter);
      const filename = `audit-logs-${organizationId}.${format}`;
      if (total > LARGE_EXPORT_THRESHOLD) {
        if (!dataExportQueue.isActive) {
          return sendError(res, 503, "Background export processing is unavailable.");
        }
        const exportRecord = await AuditLogExport.create({
          organization: organizationId,
          requestedBy: req.user.id || req.user._id,
          format,
          filters: {
            action: req.query.action || undefined,
            startDate: req.query.startDate || undefined,
            endDate: req.query.endDate || undefined,
          },
          expiresAt: new Date(Date.now() + EXPORT_TTL_MS),
        });
        await dataExportQueue.add("audit-log-export", { exportId: exportRecord._id.toString() });
        return sendSuccess(res, {
          export: {
            id: exportRecord._id,
            status: exportRecord.status,
            statusUrl: `/api/organizations/${organizationId}/audit-log-exports/${exportRecord._id}`,
            downloadUrl: `/api/organizations/${organizationId}/audit-log-exports/${exportRecord._id}/download`,
          },
        }, "Audit log export queued.", 202);
      }

      res.setHeader("Content-Type", format === "csv" ? "text/csv; charset=utf-8" : "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");
      res.setHeader("Content-Disposition", `attachment; filename="${filename}"`);
      if (format === "csv") return streamCsvExport(res, filter);
      return streamXlsxExport(res, filter);
    }

    // Execute query with pagination and populate the actor
    const logs = await AuditLog.find(filter)
      .populate("actor", "name email profilePic")
      .sort({ createdAt: -1 })
      .skip(skip)
      .limit(limitNum)
      .lean();

    const total = await AuditLog.countDocuments(filter);

    sendSuccess(res, {
      logs,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total,
        pages: Math.ceil(total / limitNum),
      },
    });
  } catch (error) {
    console.error("❌ Error fetching audit logs:", error);
    sendError(res, 500, "Server error fetching audit logs.");
  }
};

export const getAuditLogExport = async (req, res) => {
  try {
    const exportRecord = await AuditLogExport.findOne({
      _id: req.params.exportId,
      organization: req.params.id,
    }).lean();
    if (!exportRecord) return sendError(res, 404, "Audit log export not found.");
    return sendSuccess(res, {
      export: {
        id: exportRecord._id,
        status: exportRecord.status,
        downloadUrl: exportRecord.status === "completed"
          ? `/api/organizations/${req.params.id}/audit-log-exports/${exportRecord._id}/download`
          : null,
        expiresAt: exportRecord.expiresAt,
        error: exportRecord.status === "failed" ? exportRecord.error : undefined,
      },
    });
  } catch (error) {
    return sendError(res, 500, "Server error fetching audit log export.");
  }
};

export const downloadAuditLogExport = async (req, res) => {
  try {
    const exportRecord = await AuditLogExport.findOne({
      _id: req.params.exportId,
      organization: req.params.id,
      status: "completed",
    }).lean();
    if (!exportRecord) return sendError(res, 404, "Completed audit log export not found.");
    const filePath = path.join(AUDIT_EXPORT_DIRECTORY, exportRecord.fileName || "");
    if (!exportRecord.fileName || !filePath.startsWith(AUDIT_EXPORT_DIRECTORY + path.sep) || !fs.existsSync(filePath)) {
      return sendError(res, 404, "Audit log export file not found.");
    }
    return res.download(filePath, `audit-logs.${exportRecord.format}`);
  } catch (error) {
    return sendError(res, 500, "Server error downloading audit log export.");
  }
};

// ================================
// hybridSearchController.js
// Handles hybrid (semantic + knowledge-graph) memory retrieval.
// Additive to the existing /api/search (meeting-only) endpoint - existing
// clients of that route are unaffected.
// ================================

import { hybridRetrieve } from "../services/hybridRetrievalService.js";
import { getRedisClient, setSearchCache } from "../services/redisService.js";
import { sendSuccess, sendError } from "../utils/responseHandler.js";

/**
 * @desc  Hybrid retrieval: semantic vector search fused with knowledge-graph
 *        multi-hop traversal over decisions, action items and meetings.
 * @route POST /api/search/hybrid
 * @access Private (requires auth)
 *
 * Body:
 *  {
 *    query: string (required),
 *    topK?: number,                 // final result count, default 10
 *    semanticTopK?: number,         // seed candidates before graph expansion
 *    semanticWeight?: number,       // relative weight of vector similarity
 *    graphWeight?: number,          // relative weight of graph connectivity
 *    maxHops?: number,              // graph traversal depth, default 2
 *    decay?: number,                // per-hop score decay (0-1), default 0.6
 *    minEdgeWeight?: number,        // ignore weak relatesTo edges (0-100)
 *    includeTypes?: ("meeting"|"decision"|"actionItem")[]
 *  }
 */
export const hybridSearch = async (req, res) => {
  try {
    if (!req.body || Object.keys(req.body).length === 0) {
      return sendError(
        res,
        400,
        "Missing request body. Please send a valid JSON with { query: 'your question' }.",
      );
    }

    const { query, ...options } = req.body;

    if (!query || typeof query !== "string" || query.trim().length < 3) {
      return sendError(
        res,
        400,
        "Please provide a valid search query (minimum 3 characters). Example: { query: 'attendance policy' }",
      );
    }

    const organization = req.user?.organization || null;

    console.log(
      `🔀 Hybrid search for query: "${query}" (org: ${organization})`,
    );

    const { results, meta } = await hybridRetrieve(
      query,
      organization,
      options,
    );

    const message = results.length
      ? "Hybrid search successful."
      : "No relevant memories found.";

    const responsePayload = {
      success: true,
      message,
      results,
      meta,
    };

    if (req.cacheKey) {
      await setSearchCache(req.cacheKey, req.organizationId, responsePayload);
    }

    return sendSuccess(res, { results, meta }, message);
  } catch (error) {
    console.error("❌ Hybrid search error:", error);

    if (error.message === "A non-empty query string is required") {
      return sendError(res, 400, error.message);
    }

    sendError(
      res,
      500,
      error.response?.data?.error ||
        error.message ||
        "Server error during hybrid search.",
    );
  }
};

/**
 * Meeting Controller — HTTP layer only.
 *
 * Responsibilities:
 *  1. Parse and validate the incoming HTTP request (using Zod schemas).
 *  2. Delegate all business logic to MeetingService.
 *  3. Shape and send the HTTP response.
 *  4. Forward any error to the global error handler via next(err).
 *
 * This file intentionally contains NO database queries, NO AI calls, and
 * NO direct references to external APIs.  All of that lives in
 * server/services/MeetingService.js.
 */

import fs from "fs";
import path from "path";
import { z } from "zod";
import Meeting from "../models/meetingModel.js";
import * as MeetingService from "../services/MeetingService.js";
import { ValidationError, UnauthorizedError } from "../utils/errors.js";
import AuditService from "../services/AuditService.js";
import { sendSuccess } from "../utils/responseHandler.js";
import { pushMeetingToIntegrations, deleteMeetingFromIntegrations } from "../services/calendarSyncService.js";

// ═══════════════════════════════════════════════════════════════
// Zod validation schemas
// ═══════════════════════════════════════════════════════════════

const createMeetingSchema = z.object({
  title: z.string().min(1, "Meeting title is required"),
  description: z.string().optional().default(""),
  meetingType: z
    .enum(["conference", "policy", "event", "internal", "external", "board"])
    .optional()
    .default("conference"),
  date: z.string().optional(),
  time: z.string().optional().default(""),
  duration: z.number().nullable().optional(),
  location: z.string().optional().default(""),
  venue: z.string().optional().default(""),
  participants: z.array(z.record(z.unknown())).optional().default([]),
  agendaItems: z.array(z.record(z.unknown())).optional().default([]),
  policyDetails: z.record(z.unknown()).nullable().optional(),
  recordingType: z.enum(["upload", "live"]).optional().default("upload"),
});

const uploadMeetingSchema = z.object({
  title: z.string().optional(),
  date: z.string().optional(),
  meetingType: z
    .enum(["conference", "policy", "event", "internal", "external", "board"])
    .optional(),
});

const summarizeMeetingSchema = z.object({
  meetingId: z.string().optional(),
  transcript: z.string().optional(),
  date: z.string({ required_error: "Meeting date is required." }),
  title: z.string().optional(),
});

const updateMeetingSchema = z.object({
  title: z.string().min(1).optional(),
  description: z.string().optional(),
  meetingType: z
    .enum(["conference", "policy", "event", "internal", "external", "board"])
    .optional(),
  date: z.string().optional(),
  time: z.string().optional(),
  duration: z.number().nullable().optional(),
  location: z.string().optional(),
  venue: z.string().optional(),
  tags: z.array(z.string()).optional(),
});

const searchMeetingSchema = z.object({
  query: z.string().optional(),
  audioUrl: z.string().url().optional(),
});

const notifyLiveMeetingSchema = z.object({
  roomId: z.string().min(1, "roomId is required"),
  participants: z
    .array(z.object({ name: z.string(), email: z.string().optional() }))
    .min(1, "At least one participant is required"),
});

const getAllMeetingsQuerySchema = z.object({
  page: z
    .string()
    .optional()
    .transform((val) => {
      if (!val) return 1;
      const parsed = parseInt(val, 10);
      return isNaN(parsed) || parsed < 1 ? 1 : parsed;
    }),
  limit: z
    .string()
    .optional()
    .transform((val) => {
      if (!val) return 10;
      const parsed = parseInt(val, 10);
      if (isNaN(parsed) || parsed < 1) return 10;
      return parsed > 100 ? 100 : parsed; // Cap at 100
    }),
  search: z.string().optional(),
  meetingType: z.string().optional(),
  includeArchived: z
    .string()
    .optional()
    .transform((val) => val === "true"),
});

// Helper to prevent path traversal in manual file cleanup checks
const validatePath = (filePath) => {
  if (!filePath) throw new Error("Path is required");
  const resolved = path.resolve(filePath);
  const uploadsDir = path.resolve("uploads");
  if (!resolved.startsWith(uploadsDir)) {
    throw new Error("Directory traversal detected: Access denied");
  }
  return resolved;
};

// ── Helper: extract userId from the request ───────────────────
const getUserId = (req) => {
  const id = req.user?.id || req.user?._id;
  if (!id) throw new UnauthorizedError();
  return id.toString();
};

// ═══════════════════════════════════════════════════════════════
// Controller handlers
// ═══════════════════════════════════════════════════════════════

/* ─────────────────────────────────────────────────────────────
   1. CREATE MEETING (Schedule from CreateMeeting form)
   Used by: CreateMeeting.jsx "Schedule Meeting" section
   ───────────────────────────────────────────────────────────── */
export const createMeeting = async (req, res, next) => {
  try {
    const uploaderId = getUserId(req);

    let validated;
    try {
      validated = createMeetingSchema.parse(req.body);
    } catch (zodErr) {
      return next(zodErr); // ZodError → errorHandler → 400
    }

    const meeting = await MeetingService.createMeeting(
      uploaderId,
      req.user?.organization || null,
      validated,
    );

    if (req.body.syncToCalendar) {
      pushMeetingToIntegrations(uploaderId, meeting).catch(console.error);
    }

    return sendSuccess(
      res,
      {
        meeting: {
          _id: meeting._id,
          title: meeting.title,
          meetingType: meeting.meetingType,
          date: meeting.date,
        },
      },
      "Meeting scheduled successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   2. UPLOAD MEETING (Original - from UploadMeeting page)
   Used by: UploadMeeting.jsx
   ───────────────────────────────────────────────────────────── */
export const uploadMeeting = async (req, res, next) => {
  const uploadedFilePath = req.file?.path || null;

  try {
    if (!req.file) {
      throw new ValidationError("No audio file uploaded.");
    }
    const uploaderId = getUserId(req);

    let validated;
    try {
      validated = uploadMeetingSchema.parse(req.body);
    } catch (zodErr) {
      // Clean up the uploaded file on validation failure before routing
      if (uploadedFilePath) {
        try {
          const safePath = validatePath(uploadedFilePath);
          if (fs.existsSync(safePath)) {
            fs.unlinkSync(safePath);
          }
        } catch {
          // ignore cleanup errors
        }
      }
      throw zodErr;
    }

    const { meeting, transcript } =
      await MeetingService.uploadAndTranscribeMeeting(
        uploaderId,
        req.user?.organization || null,
        req.file,
        validated,
      );

    return sendSuccess(
      res,
      {
        meetingId: meeting._id,
        transcript,
      },
      "Meeting transcribed successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   3. UPLOAD AUDIO FOR EXISTING MEETING
   Used by: CreateMeeting.jsx "Upload Meeting" section
   ───────────────────────────────────────────────────────────── */
export const uploadAudioForMeeting = async (req, res, next) => {
  try {
    if (!req.file) {
      throw new ValidationError("No audio file uploaded.");
    }
    const uploaderId = getUserId(req);
    const { meetingId } = req.body;

    if (!meetingId) {
      throw new ValidationError("Meeting ID is required");
    }

    const { meeting, transcript } =
      await MeetingService.uploadAudioForExistingMeeting(
        uploaderId,
        meetingId,
        req.file,
      );

    return sendSuccess(
      res,
      {
        meetingId: meeting._id,
        transcript,
      },
      "Audio uploaded and transcribed successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   4. SUMMARIZE MEETING (Generate AI MOM)
   Used by: UploadMeeting.jsx and CreateMeeting.jsx
   ───────────────────────────────────────────────────────────── */
export const summarizeMeeting = async (req, res, next) => {
  try {
    const userId = getUserId(req);

    let validated;
    try {
      validated = summarizeMeetingSchema.parse(req.body);
    } catch (zodErr) {
      return next(zodErr);
    }

    const result = await MeetingService.generateMeetingMoM(
      userId,
      validated.meetingId || null,
      validated.transcript || "",
      validated.date,
      validated.title || null,
    );

    if (result.queued) {
      return sendSuccess(
        res,
        null,
        "Minutes generation started in the background. Please wait...",
        202,
      );
    }

    return sendSuccess(
      res,
      {
        mom: result.mom,
        momText: result.momText,
        meetingId: result.meetingId,
      },
      "Minutes generated successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   5. GET ALL MEETINGS (Dashboard)
   Used by: Dashboard / Summaries page
   ───────────────────────────────────────────────────────────── */
export const getAllMeetings = async (req, res, next) => {
  try {
    const userId = getUserId(req);

    let validatedQuery;
    try {
      validatedQuery = getAllMeetingsQuerySchema.parse(req.query);
    } catch (zodErr) {
      return next(zodErr);
    }

    const { meetings, pagination } = await MeetingService.getAllMeetings(
      userId,
      req.user?.organization || null,
      validatedQuery,
    );

    return sendSuccess(res, { meetings, pagination });
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   6. DELETE MEETING
   ───────────────────────────────────────────────────────────── */
export const deleteMeeting = async (req, res, next) => {
  try {
    await MeetingService.deleteMeeting(
      req.doc || null, // from requireOwnerOrAdmin middleware (may be undefined)
      req.params.id,
    );

    if (req.doc && req.doc.organization) {
      AuditService.logAction({
        actorId: getUserId(req),
        action: "MEETING_DELETED",
        entity: "Meeting",
        entityId: req.doc._id,
        organizationId: req.doc.organization,
        details: { title: req.doc.title },
      });
    }

    return sendSuccess(res, null, "Meeting deleted successfully");
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   7. GET MEETING BY ID
   Used by: MeetingDetails.jsx
   ───────────────────────────────────────────────────────────── */
export const getMeetingById = async (req, res, next) => {
  try {
    getUserId(req); // ensure authenticated
    const meeting = await MeetingService.getMeetingById(req.params.id);
    return sendSuccess(res, { meeting });
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   8. UPDATE MEETING (Rename / edit fields)
   Used by: MeetingDetails.jsx
   ───────────────────────────────────────────────────────────── */
export const updateMeeting = async (req, res, next) => {
  try {
    const userId = getUserId(req);

    let validated;
    try {
      validated = updateMeetingSchema.parse(req.body);
    } catch (zodErr) {
      return next(zodErr);
    }

    const meeting = await MeetingService.updateMeeting(
      userId,
      req.params.id,
      validated,
      req.doc || null, // from requireOwner middleware
    );

    return sendSuccess(
      res,
      {
        meeting: {
          _id: meeting._id,
          title: meeting.title,
          description: meeting.description,
          meetingType: meeting.meetingType,
          date: meeting.date,
        },
      },
      "Meeting updated successfully",
    );
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
   9. VOICE / TEXT SEARCH
   Used by: Search page
   ───────────────────────────────────────────────────────────── */
export const searchMeetingsByText = async (req, res, next) => {
  try {
    const userId = getUserId(req);
    const orgId = req.user?.organization || null;

    let validated;
    try {
      validated = searchMeetingSchema.parse(req.body);
    } catch (zodErr) {
      return next(zodErr);
    }

    const result = await MeetingService.searchMeetings(
      validated,
      orgId,
      userId,
    );

    return sendSuccess(res, result);
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
    10. ARCHIVE MEETING
    ───────────────────────────────────────────────────────────── */
export const archiveMeeting = async (req, res, next) => {
  try {
    getUserId(req);
    const meeting = await MeetingService.archiveMeeting(req.params.id);
    return res.status(200).json({
      success: true,
      message: "Meeting archived successfully",
      meeting: { _id: meeting._id, archived: meeting.archived },
    });
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
    11. RESTORE MEETING
    ───────────────────────────────────────────────────────────── */
export const restoreMeeting = async (req, res, next) => {
  try {
    getUserId(req);
    const meeting = await MeetingService.restoreMeeting(req.params.id);
    return res.status(200).json({
      success: true,
      message: "Meeting restored successfully",
      meeting: { _id: meeting._id, archived: meeting.archived },
    });
  } catch (err) {
    next(err);
  }
};

/* ─────────────────────────────────────────────────────────────
    12. NOTIFY LIVE MEETING PARTICIPANTS
    ───────────────────────────────────────────────────────────── */
export const notifyLiveMeeting = async (req, res, next) => {
  try {
    const uploaderId = getUserId(req);

    let validated;
    try {
      validated = notifyLiveMeetingSchema.parse(req.body);
    } catch (zodErr) {
      return next(zodErr);
    }

    const { count } = await MeetingService.notifyLiveMeetingParticipants(
      uploaderId,
      validated.roomId,
      validated.participants,
      req.user.organization,
    );

    return sendSuccess(res, { count }, "Participants notified");
  } catch (err) {
    next(err);
  }
};

// ================================
// searchController.js
// Handles semantic AI-powered search for meetings
// ================================

import { searchVectorStore } from "../utils/embeddingUtils.js";
import Meeting from "../models/meetingModel.js";
import Membership from "../models/membershipModel.js";
import { getRedisClient, setSearchCache } from "../services/redisService.js";
import { buildExplanation } from "../utils/explanationBuilder.js";
import { sendSuccess, sendError } from "../utils/responseHandler.js";

/**
 * @desc  Search meetings using AI embeddings
 * @route POST /api/search
 * @access Private (requires auth)
 */
export const semanticSearch = async (req, res) => {
  try {
    // ✅ Step 1 — Defensive check for body
    if (!req.body || Object.keys(req.body).length === 0) {
      return sendError(
        res,
        400,
        "Missing request body. Please send a valid JSON with { query: 'your question' }.",
      );
    }

    // ✅ Step 2 — Extract query safely
    const { query } = req.body;

    if (!query || typeof query !== "string" || query.trim().length < 3) {
      return sendError(
        res,
        400,
        "Please provide a valid search query (minimum 3 characters). Example: { query: 'attendance policy' }",
      );
    }

    console.log(`🔍 AI Semantic Search for query: "${query}"`);

    // ✅ Step 3 — Perform vector search
    const results = await searchVectorStore(query);

    if (!results || results.length === 0) {
      return sendSuccess(res, { results: [] }, "No relevant meetings found.");
    }

    // ✅ Step 4 — Get user's active organizations for access control
    const memberships = await Membership.find(
      { user: req.user._id, status: "active" },
      "organization",
    ).lean();
    const userOrgIds = memberships.map((m) => m.organization.toString());

    // ✅ Step 5 — Fetch full meeting data for context, scoped to user's orgs
    const meetingIds = results.map((r) => r.meetingId);
    const meetings = await Meeting.find({
      _id: { $in: meetingIds },
      $or: [
        { organization: { $in: userOrgIds } },
        { uploadedBy: req.user._id },
      ],
    })
      .select("title summary createdAt")
      .lean();

    // ✅ Step 6 — Merge vector results with DB data and filter out deleted meetings
    const mergedResults = results
      .map((r, index) => {
        const m = meetings.find((mt) => mt._id.toString() === r.meetingId);
        // Defense in depth: only return results that still exist in MongoDB
        if (!m) return null;
        return {
          meetingId: r.meetingId,
          title: m?.title || r.title || "Untitled Meeting",
          summary: m?.summary || r.summary || "No summary available.",
          score: (1 - r.similarityScore).toFixed(3),
          createdAt: m?.createdAt || null,
          // FEATURE #270: human-readable explanation of why this result was
          // returned. Meetings don't carry graph/access-history data today
          // (see server/graph/graphIndex.js), so those fields are honestly
          // reported as not applicable rather than faked.
          explanation: buildExplanation({
            type: "meeting",
            semanticScore: r.similarityScore || 0,
            vectorRank: index + 1,
          }),
        };
      })
      .filter((r) => r !== null);

    const responsePayload = {
      results: mergedResults,
    };

    // ✅ Step 7 — Save to Redis Cache (if applicable)
    if (req.cacheKey) {
      await setSearchCache(req.cacheKey, req.organizationId, responsePayload);
    }

    // ✅ Step 8 — Send response
    return sendSuccess(res, responsePayload, "AI Search successful.");
  } catch (error) {
    console.error("❌ Semantic search error:", error);
    const message =
      error.response?.data?.error ||
      error.message ||
      "Server error during semantic search.";
    sendError(res, 500, message);
  }
};

// server/controllers/slackController.js
/**
 * Slack Controller — HTTP layer only.
 *
 * Handles the three Slack-facing endpoints:
 *  GET  /api/slack/install          → Redirect user to Slack's OAuth consent page
 *  GET  /api/slack/oauth_redirect   → Exchange one-time code for bot token; save to org
 *  POST /api/slack/events           → Receive all Slack event/slash payloads
 *
 * Request signature verification (Slack Signing Secret) is applied as a
 * middleware for the /events endpoint. OAuth endpoints are safe because
 * they use the code parameter provided by Slack's own redirect.
 */

import Organization from "../models/organizationModel.js";
import User from "../models/userModel.js";
import jwt from "jsonwebtoken";
import { hasPermission } from "../utils/rbacPermissions.js";
import * as MeetingService from "../services/MeetingService.js";
import {
  verifySlackSignature,
  exchangeSlackCodeForToken,
  buildMeetingCreatedBlocks,
} from "../services/slackService.js";
import { sendError } from "../utils/responseHandler.js";

// Helpers

/**
 * Parse the text portion of a Slack slash command.
 
 * The convention we support:
 *   /mom-create "Meeting Title" @optionalTag
 
 * Returns { title, tags } where title is the quoted string (or the full
 * trimmed text when no quotes are used) and tags is an array of @-mentions.
 
 * @param {string} text - Raw command text from Slack payload
 * @returns {{ title: string, tags: string[] }}
 */
const parseSlashCommandText = (text = "") => {
  const trimmed = text.trim();

  // Match a quoted string at the start: "Q3 Planning" or 'Q3 Planning'
  const quotedMatch = trimmed.match(/^["'](.+?)["']/);
  const title = quotedMatch
    ? quotedMatch[1].trim()
    : trimmed.replace(/@\S+/g, "").trim();

  // Collect all @-mentions from the full text
  const tags = [...trimmed.matchAll(/@(\S+)/g)].map((m) => m[1]);

  return { title: title || "Untitled Meeting", tags };
};

// 1. GET /api/slack/install

/**
 * Redirects the authenticated user to Slack's OAuth consent page.
 * The `organizationId` is embedded in the OAuth `state` parameter so we can
 * associate the resulting bot token with the correct organization.
 
 * @param {import('express').Request}  req
 * @param {import('express').Response} res
 * @param {import('express').NextFunction} next
 */
export const slackInstall = async (req, res, next) => {
  try {
    const clientId = process.env.SLACK_CLIENT_ID;
    if (!clientId) {
      return sendError(
        res,
        500,
        "Slack integration is not configured on this server.",
      );
    }

    // organizationId can come from an authenticated request (query or user object)
    let organizationId =
      req.query.organizationId || req.user?.organization?.toString() || "";

    if (
      typeof organizationId !== "string" ||
      !/^[0-9a-fA-F]{24}$/.test(organizationId)
    ) {
      return sendError(res, 400, "Invalid or missing organizationId format.");
    }

    // Generate JWT for state to protect against CSRF and verify authorization on callback
    const stateToken = jwt.sign(
      { orgId: organizationId, userId: req.user._id.toString() },
      process.env.JWT_SECRET,
      { expiresIn: "15m" },
    );

    const redirectUri = process.env.SLACK_REDIRECT_URI;
    const scopes = "commands,chat:write,channels:read";

    const params = new URLSearchParams({
      client_id: clientId,
      scope: scopes,
      state: stateToken,
      ...(redirectUri && { redirect_uri: redirectUri }),
    });

    return res.redirect(
      `https://slack.com/oauth/v2/authorize?${params.toString()}`,
    );
  } catch (err) {
    return next(err);
  }
};

// 2. GET /api/slack/oauth_redirect

/**
 * Handles the redirect from Slack after the user approves the OAuth flow.
 * Exchanges the temporary `code` for a permanent bot token and saves the
 * Slack integration details to the matching Organization document.
 * @param {import('express').Request}  req
 * @param {import('express').Response} res
 * @param {import('express').NextFunction} next
 */
export const slackOAuthRedirect = async (req, res, next) => {
  try {
    const { code, state: stateToken, error: slackError } = req.query;

    const frontendUrl = process.env.FRONTEND_URL || "http://localhost:5173";

    if (!stateToken || typeof stateToken !== "string") {
      return sendError(res, 400, "Missing OAuth state.");
    }

    let decodedState;
    try {
      decodedState = jwt.verify(stateToken, process.env.JWT_SECRET);
    } catch (err) {
      return sendError(res, 400, "Invalid or expired OAuth state.");
    }

    const organizationId = decodedState.orgId;
    const userId = decodedState.userId;

    // Handle user-denied or Slack error cases
    if (slackError) {
      const sanitizedError = encodeURIComponent(String(slackError));
      return res.redirect(
        `${frontendUrl}/organizations/${organizationId}?slackInstall=error&reason=${sanitizedError}`,
      );
    }

    if (!code || typeof code !== "string") {
      return sendError(res, 400, "Missing or invalid OAuth code from Slack.");
    }

    // Verify the user who initiated the install is still authorized for this org
    const user = await User.findById(userId);
    if (!user || user.organization?.toString() !== organizationId) {
      return sendError(res, 403, "Unauthorized organization binding.");
    }

    if (!hasPermission(user.role || "guest", "settings", "edit")) {
      return sendError(
        res,
        403,
        "Insufficient permissions to install integrations.",
      );
    }

    // Verify the organization exists before persisting anything
    const org = await Organization.findById(organizationId);
    if (!org) {
      return sendError(res, 404, "Organization not found.");
    }

    // Exchange the code for a bot token
    const slackData = await exchangeSlackCodeForToken(code);

    // Persist the integration details
    // slackData.access_token  = the bot token (xoxb-...)
    // slackData.incoming_webhook.channel_id = the channel the user selected
    // slackData.team.id / slackData.team.name = the Slack workspace info
    await Organization.findByIdAndUpdate(organizationId, {
      $set: {
        "slackIntegration.botToken": slackData.access_token,
        "slackIntegration.channelId":
          slackData.incoming_webhook?.channel_id || "",
        "slackIntegration.teamId": slackData.team?.id || "",
        "slackIntegration.teamName": slackData.team?.name || "",
        "slackIntegration.installedAt": new Date(),
      },
    });

    console.log(
      `✅ [Slack] Workspace "${slackData.team?.name}" connected to org ${organizationId}`,
    );

    // Redirect user back to the organization page in the frontend
    return res.redirect(
      `${frontendUrl}/organizations/${organizationId}?slackInstall=success`,
    );
  } catch (err) {
    return next(err);
  }
};

// 3. POST /api/slack/events

/**
 * Central handler for all incoming Slack payloads:
 *   - URL verification challenge (for initial Slack Event API setup)
 *   - Slash command: /mom-create
 *   - Slack Event Subscriptions (future extension point)
 * Signature verification is performed BEFORE reaching this handler via the
 * `slackSignatureMiddleware` applied in slackRoutes.js.
 *
 * @param {import('express').Request}  req
 * @param {import('express').Response} res
 * @param {import('express').NextFunction} next
 */
export const handleSlackEvents = async (req, res, next) => {
  try {
    const body = req.body;

    // Case 1: Slack URL verification handshake
    // Slack sends this once when you first configure the Events API URL.
    if (body?.type === "url_verification") {
      return res.status(200).json({ challenge: body.challenge });
    }

    // Case 2: Slash command: /mom-create
    // Slack sends slash commands as application/x-www-form-urlencoded POST.
    // req.body will be parsed because express.urlencoded is active.
    if (body?.command === "/mom-create") {
      const text = typeof body.text === "string" ? body.text : "";
      const { title, tags } = parseSlashCommandText(text);
      const teamId = typeof body.team_id === "string" ? body.team_id : "";
      const userName =
        typeof body.user_name === "string" ? body.user_name : "someone";

      if (!teamId) {
        return res.status(200).json({
          response_type: "ephemeral",
          text: "❌ Could not identify your Slack workspace. Please re-install the bot.",
        });
      }

      // Find the organization linked to this Slack workspace
      // Using string coercion on teamId to prevent NoSQL query injection
      const org = await Organization.findOne({
        "slackIntegration.teamId": String(teamId),
      }).lean();

      if (!org) {
        return res.status(200).json({
          response_type: "ephemeral",
          text: `❌ Your Slack workspace is not connected to any MeetOnMemory organization.\nVisit your organization settings and click *Connect Slack* to get started.`,
        });
      }

      if (!title) {
        return res.status(200).json({
          response_type: "ephemeral",
          text: '❌ Please provide a meeting title. Usage: `/mom-create "Q3 Planning" @team`',
        });
      }

      // Create the meeting using the MeetingService
      // We pass null as userId (no authenticated user in slash commands);
      // the meeting is attributed to the organization's owner.
      const meeting = await MeetingService.createMeeting(
        org.owner.toString(), // userId — use org owner as the author
        org._id.toString(), // organizationId
        {
          title,
          description: tags.length
            ? `Created via Slack by @${userName}. Participants: ${tags.join(", ")}`
            : `Created via Slack by @${userName}`,
          meetingType: "conference",
          date: new Date().toISOString(),
          tags,
        },
        null, // io — socket not available in this context
      );

      // Respond immediately with a Block Kit message (Slack requires <3 s response)
      const blocks = buildMeetingCreatedBlocks(meeting, `@${userName}`);
      return res.status(200).json({
        response_type: "in_channel",
        text: `✅ Meeting "${title}" created by @${userName}`,
        blocks,
      });
    }

    // Case 3: Standard Slack Event Subscriptions
    // Acknowledge all other events with a 200 OK immediately (Slack requires this)
    // and process asynchronously if needed in the future.
    if (body?.type === "event_callback") {
      // Acknowledge first — Slack retries if no 200 within 3 seconds
      res.status(200).send();

      const event = body.event;
      console.log(
        `ℹ️ [Slack] Received event: ${event?.type} from team ${body.team_id}`,
      );
      // Future: handle app_mention, message events, etc.
      return;
    }

    // Default: acknowledge unknown payload types
    return res.status(200).send();
  } catch (err) {
    return next(err);
  }
};

// Middleware: Verify Slack Signing Secret

/**
 * Express middleware that verifies the Slack request signature.
 * Applied only to the /events POST endpoint.
 * Skipped in test environment (NODE_ENV === "test") to allow Jest to call freely.
 *
 * @param {import('express').Request}  req
 * @param {import('express').Response} res
 * @param {import('express').NextFunction} next
 */
export const slackSignatureMiddleware = (req, res, next) => {
  // In test environments, skip signature verification to allow integration tests
  if (process.env.NODE_ENV === "test") {
    return next();
  }

  const { valid, reason } = verifySlackSignature(req);
  if (!valid) {
    console.warn(`⚠️ [Slack] Invalid signature rejected: ${reason}`);
    return res.status(401).json({ error: "Invalid Slack request signature." });
  }
  return next();
};

import userModel from "../models/userModel.js";
import { dataExportQueue } from "../services/queueService.js";
import jwt from "jsonwebtoken";
import path from "path";
import fs from "fs";
import { fileURLToPath } from "url";
import { sendSuccess, sendError } from "../utils/responseHandler.js";

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const formatUserResponse = (user) => {
  return {
    id: user._id,
    name: user.name,
    email: user.email,
    isAccountVerified: user.isAccountVerified,
    role: user.role,
    hasCompletedOnboarding: user.hasCompletedOnboarding,
    organization: user.organization,
    profilePic: user.profilePic || "",
    bio: user.bio || "",
    createdAt: user.createdAt,
  };
};

// @desc    Get user data
// @route   GET /api/user/get-user
// @access  Private
export const getUserData = async (req, res) => {
  try {
    // --- SAFETY CHECK ---
    if (!req.user || !req.user.id) {
      return sendError(res, 401, "Authentication error, user ID not found.");
    }

    // Now this line is safe to run
    const user = await userModel
      .findById(req.user.id)
      .select("-password")
      .populate("organization", "name logo");

    if (user) {
      sendSuccess(res, { user: formatUserResponse(user) });
    } else {
      return sendError(res, 404, "User not found in database");
    }
  } catch (error) {
    console.error("Error in getUserData:", error);
    sendError(res, 500, "Server error");
  }
};

// @desc    Update user profile
// @route   PUT /api/user/update
// @access  Private
export const updateUserProfile = async (req, res) => {
  try {
    const { name, profilePic, bio } = req.body;

    if (!req.user || !req.user.id) {
      return sendError(res, 401, "Authentication error, user ID not found.");
    }

    // Validation
    if (!name || name.trim() === "") {
      return sendError(res, 400, "Name is required.");
    }

    if (profilePic && profilePic.trim() !== "") {
      let parsed;
      try {
        parsed = new URL(profilePic.trim());
      } catch {
        return sendError(res, 400, "Profile picture must be a valid URL.");
      }
      if (!["http:", "https:"].includes(parsed.protocol)) {
        return sendError(res, 400, "Image URL must use http or https.");
      }
    }

    const updatedUser = await userModel
      .findByIdAndUpdate(
        req.user.id,
        {
          $set: {
            name: name.trim(),
            profilePic: profilePic ? profilePic.trim() : "",
            bio: bio ? bio.trim() : "",
          },
        },
        { new: true },
      )
      .populate("organization", "name logo");

    if (!updatedUser) {
      return sendError(res, 404, "User not found.");
    }

    sendSuccess(
      res,
      { user: formatUserResponse(updatedUser) },
      "Profile updated successfully.",
    );
  } catch (error) {
    console.error("Error in updateUserProfile:", error);
    sendError(res, 500, "Server error");
  }
};

// @desc    Request data export
// @route   POST /api/user/request-data-export
// @access  Private
export const requestDataExport = async (req, res) => {
  try {
    if (!req.user || !req.user.id) {
      return sendError(res, 401, "Authentication error, user ID not found.");
    }

    const user = await userModel.findById(req.user.id);
    if (!user) {
      return sendError(res, 404, "User not found.");
    }

    if (dataExportQueue) {
      await dataExportQueue.add("export", {
        userId: user._id.toString(),
        email: user.email,
      });

      return sendSuccess(
        res,
        null,
        "Data export request accepted. You will receive an email when it is ready.",
        202,
      );
    } else {
      return sendError(
        res,
        503,
        "Background processing service is currently unavailable.",
      );
    }
  } catch (error) {
    console.error("Error in requestDataExport:", error);
    sendError(res, 500, "Server error");
  }
};

// @desc    Download data export
// @route   GET /api/user/download-export/:token
// @access  Public (Token verification acts as auth)
export const downloadExport = async (req, res) => {
  try {
    const { token } = req.params;
    if (!token) {
      return sendError(res, 400, "No token provided.");
    }

    const jwtSecret = process.env.JWT_SECRET;

    let decoded;
    try {
      decoded = jwt.verify(token, jwtSecret);
    } catch (err) {
      return sendError(res, 401, "Invalid or expired token.");
    }

    const { fileName } = decoded;
    if (!fileName) {
      return sendError(res, 400, "Invalid token payload.");
    }

    const exportDir = path.join(__dirname, "..", "uploads", "exports");
    const filePath = path.join(exportDir, fileName);

    if (!filePath.startsWith(exportDir)) {
      return sendError(res, 403, "Invalid file path.");
    }

    if (!fs.existsSync(filePath)) {
      return sendError(res, 404, "Export file not found or has been deleted.");
    }

    res.download(filePath, "data_export.zip", (err) => {
      if (err) {
        console.error("Error sending file:", err);
        // Don't send another response if headers are already sent
        if (!res.headersSent) {
          sendError(res, 500, "Error downloading file.");
        }
      }
    });
  } catch (error) {
    console.error("Error in downloadExport:", error);
    sendError(res, 500, "Server error");
  }
};

import mongoose from "mongoose";
import { URL } from "url";
import { z } from "zod";
import Webhook from "../models/Webhook.js";
import WebhookDelivery from "../models/WebhookDelivery.js";
import { redeliverWebhookDelivery } from "../services/webhookDispatcherService.js";
import Membership from "../models/membershipModel.js";
import Organization from "../models/organizationModel.js";
import {
  ValidationError,
  UnauthorizedError,
  ForbiddenError,
  NotFoundError,
} from "../utils/errors.js";
import { sendSuccess } from "../utils/responseHandler.js";

import dns from "dns/promises";
import ipaddr from "ipaddr.js";

const isSafeWebhookUrl = async (urlStr) => {
  try {
    const parsed = new URL(urlStr);
    const hostname = parsed.hostname.toLowerCase();

    // Block obvious localhosts immediately
    if (hostname === "localhost" || hostname === "localhost.localdomain") {
      return false;
    }

    // Resolve the hostname to an IP address
    let resolvedIp;
    try {
      // dns.lookup checks /etc/hosts and DNS, returning the IP
      const { address } = await dns.lookup(hostname);
      resolvedIp = address;
    } catch (err) {
      // If we can't resolve it, it's not a valid safe public URL
      return false;
    }

    // Parse the resolved IP using ipaddr.js
    let addr;
    try {
      addr = ipaddr.parse(resolvedIp);
    } catch (err) {
      return false;
    }

    // Check if the address is in a private, loopback, link-local, or otherwise restricted range
    const range = addr.range();

    // ipaddr.js classifies public addresses as 'unicast'
    // Private ranges are classified as 'private', 'loopback', 'linkLocal', etc.
    if (range !== "unicast") {
      return false;
    }

    // Explicitly block known IPv4 mapped IPv6 loopbacks just in case
    if (addr.kind() === "ipv6" && addr.isIPv4MappedAddress()) {
      const v4addr = addr.toIPv4Address();
      if (v4addr.range() !== "unicast") {
        return false;
      }
    }

    return true;
  } catch (err) {
    return false;
  }
};

// Helper to verify user permissions (must be Owner or Admin of the target Organization)
const hasAdminPermission = async (userId, organizationId) => {
  if (!organizationId) return false;

  try {
    const org = await Organization.findById(organizationId);
    if (!org) return false;

    // Check if user is the direct owner of the organization
    if (org.owner.toString() === userId.toString()) {
      return true;
    }

    // Check if user has an active admin membership role
    const membership = await Membership.findOne({
      user: userId,
      organization: organizationId,
      role: "admin",
      status: "active",
    }).lean();

    return !!membership;
  } catch (err) {
    console.error("Error checking permissions:", err);
    return false;
  }
};

// ═══════════════════════════════════════════════════════════════
// Zod schemas for payload validation
// ═══════════════════════════════════════════════════════════════

const createWebhookSchema = z.object({
  targetUrl: z
    .string({ required_error: "Target URL is required." })
    .trim()
    .min(1, "Target URL cannot be empty.")
    .refine((url) => url.startsWith("http://") || url.startsWith("https://"), {
      message: "Target URL must start with http:// or https://.",
    })
    .refine((url) => isSafeWebhookUrl(url), {
      message:
        "Target URL must be a public, safe address. Local/private addresses are not permitted.",
    }),
  events: z
    .array(z.enum(["meeting.created", "mom.generated", "policy.updated"]), {
      required_error: "At least one event trigger must be specified.",
    })
    .min(1, "At least one event trigger must be specified."),
  secret: z.string().trim().optional(),
  organizationId: z
    .string({ required_error: "Valid Organization ID is required." })
    .refine((val) => mongoose.Types.ObjectId.isValid(val), {
      message: "Valid Organization ID is required.",
    }),
});

const updateWebhookSchema = z.object({
  targetUrl: z
    .string()
    .trim()
    .min(1, "Target URL cannot be empty.")
    .refine((url) => url.startsWith("http://") || url.startsWith("https://"), {
      message: "Target URL must start with http:// or https://.",
    })
    .refine((url) => isSafeWebhookUrl(url), {
      message:
        "Target URL must be a public, safe address. Local/private addresses are not permitted.",
    })
    .optional(),
  events: z
    .array(z.enum(["meeting.created", "mom.generated", "policy.updated"]))
    .min(1, "At least one event trigger must be specified.")
    .optional(),
  secret: z.string().trim().min(1, "Secret key cannot be empty.").optional(),
  isActive: z.boolean().optional(),
});

// Helper to get authenticated user ID
const getUserId = (req) => {
  const id = req.user?.id || req.user?._id;
  if (!id) throw new UnauthorizedError();
  return id.toString();
};

/**
 * 🟢 Register a new Webhook subscription
 * POST /api/webhooks
 */
export const createWebhook = async (req, res, next) => {
  try {
    const userId = getUserId(req);

    let validated;
    try {
      validated = await createWebhookSchema.parseAsync(req.body);
    } catch (zodErr) {
      return next(zodErr);
    }

    // Authorization check
    const isAuthorized = await hasAdminPermission(
      userId,
      validated.organizationId,
    );
    if (!isAuthorized) {
