import axios from "axios";
import { GoogleGenerativeAI } from "@google/generative-ai";
import { pipeline, env } from "@xenova/transformers";

env.useBrowserCache = false;
let localSummarizer = null;

const HUGGINGFACE_API_KEY = process.env.HUGGINGFACE_API_KEY;
const GEMINI_API_KEY = process.env.GEMINI_API_KEY;
const GEMINI_MODEL = process.env.GEMINI_MODEL || "gemini-2.5-flash";

export const generateMoMWithAI = async (textToSummarize, date, title) => {
  const prompt = `
You are an advanced AI meeting assistant responsible for preparing *formal, well-structured Minutes of Meeting (MoM)* 
from the transcript provided below.

The MoM should be factual, concise, and formatted for professional use in organizations, universities, or institutions.  
Avoid repetition, filler words, and unnecessary phrases. Capture key insights, outcomes, and responsibilities accurately.

🎯 Your goal is to return a clean JSON object with the following fields:
{
  "title": "A clear, professional meeting title (e.g., 'AI Integration Strategy Discussion')",
  "date": "${date}",
  "summary": "A concise 4–6 sentence paragraph summarizing the meeting objectives, key points discussed, and overall conclusions. Use formal tone.",
  "agenda": ["main agenda point 1", "main agenda point 2", "main agenda point 3"],
  "key_discussions": [
    "Summarize core discussion points or debates in neutral and objective language.",
    "Mention who contributed if identifiable (optional)."
  ],
  "decisions": [
    "List final decisions or outcomes agreed upon during the meeting, if any."
  ],
  "action_items": [
    {"task": "Describe the specific task or next step", "owner": "Person responsible (if mentioned)", "due_date": "Deadline or expected date, if mentioned", "status": "Status if mentioned (e.g., 'pending', 'in progress', 'completed')"}
  ],
  "questions_raised": [
    "List important unanswered questions or follow-up discussions that emerged during the meeting."
  ],
  "keywords": [
    "Extract 5-10 relevant keywords and topics discussed during the meeting."
  ],
  "attendees": ["List attendees if mentioned or infer from transcript"],
  "notes": "Include any follow-up requirements, risks, or additional remarks worth noting."
}

Transcript:
${textToSummarize}

🧠 Instructions:
- Return ONLY valid JSON (no Markdown, no commentary, no backticks).
- Write in clear, formal English.
- Ensure every array key is present — use [] or "" for missing info.
- Avoid hallucinating or adding extra information.
- Maintain factual tone based on transcript content only.
- If user provided a title: ${title || "none"}, incorporate or refine it if appropriate.
`;

  try {
    console.log(`📡 Using Gemini model: ${GEMINI_MODEL}`);
    const genAI = new GoogleGenerativeAI(GEMINI_API_KEY);
    const model = genAI.getGenerativeModel({ model: GEMINI_MODEL });
    const result = await model.generateContent(prompt);
    const outputText = result.response.text();

    let structured;
    try {
      structured = JSON.parse(outputText);
    } catch {
      const match = outputText.match(/\{[\s\S]*\}/);
      structured = match ? JSON.parse(match[0]) : { rawText: outputText };
    }
    console.log("✅ Gemini response received");
    return structured;
  } catch (gemErr) {
    console.error(
      "❌ Gemini API error, falling back to HuggingFace:",
      gemErr.message,
    );
  }

  try {
    if (!localSummarizer) {
      console.log("⏳ Loading local summarization model fallback...");
      localSummarizer = await pipeline("summarization", "Xenova/distilbart-cnn-6-6");
      console.log("✅ Local model loaded");
    }

    const result = await localSummarizer(textToSummarize.substring(0, 1024), {
      max_new_tokens: 150,
    });
    
    const hfText = result[0].summary_text;

    console.log("✅ Local fallback summarization completed");
    return {
      title: title || `Meeting on ${date}`,
      date,
      summary: hfText,
      agenda: [],
      key_discussions: [],
      decisions: [],
      action_items: [],
      questions_raised: [],
      keywords: [],
      attendees: [],
      notes: "Generated using local fallback summarization model",
    };
  } catch (hfErr) {
    console.error("❌ Local fallback also failed:", hfErr.message);
    throw new Error("Both Gemini and Local fallback summarization failed");
  }
};

/**
 * AI-powered contradiction classification for two candidate-conflicting
 * memory texts (see services/conflictDetection/ContradictionAnalyzer.js).
 * Used to refine/explain conflicts already flagged by the fast, offline
 * heuristic in utils/contradictionSignals.js — never as the sole signal,
 * so the pipeline degrades gracefully when no API key is configured.
 *
 * Returns null (rather than throwing) on any failure or missing
 * configuration, so callers can fall back to the heuristic result.
 */
export const classifyContradiction = async (textA, textB) => {
  if (!GEMINI_API_KEY) return null;

  const prompt = `
You are analyzing two statements extracted from an organization's meeting
knowledge graph to determine whether they contradict each other.

Statement A: "${textA}"
Statement B: "${textB}"

Classify their relationship as exactly one of:
- "contradiction": they cannot both be true at the same time (e.g. a
  deadline, owner, or decision was recorded differently)
- "entailment": they are paraphrases / restatements of the same fact
- "neutral": unrelated, or one is a natural update/continuation that
  doesn't conflict (e.g. a status change from "open" to "resolved")

Return ONLY a JSON object, no Markdown, no commentary:
{
  "relation": "contradiction" | "entailment" | "neutral",
  "confidence": <integer 0-100>,
  "explanation": "<one concise sentence, plain English, for a non-technical reviewer>"
}
`;

  try {
    const genAI = new GoogleGenerativeAI(GEMINI_API_KEY);
    const model = genAI.getGenerativeModel({ model: GEMINI_MODEL });
    const result = await model.generateContent(prompt);
    const outputText = result.response.text();

    let parsed;
    try {
      parsed = JSON.parse(outputText);
    } catch {
      const match = outputText.match(/\{[\s\S]*\}/);
      parsed = match ? JSON.parse(match[0]) : null;
    }

    if (
      !parsed ||
      !["contradiction", "entailment", "neutral"].includes(parsed.relation)
    ) {
      return null;
    }

    return {
      relation: parsed.relation,
      confidence: Math.max(0, Math.min(100, Number(parsed.confidence) || 0)),
      explanation: String(parsed.explanation || "").slice(0, 500),
    };
  } catch (err) {
    console.error(
      "❌ Gemini contradiction classification failed:",
      err.message,
    );
    return null;
  }
};

export const normalizeMoM = (structured, title, date) => ({
  title: structured.title || title || `Meeting on ${date}`,
  date: structured.date || date,
  summary: structured.summary || structured.rawText || "",
  agenda: structured.agenda || [],
  key_discussions: structured.key_discussions || [],
  decisions: structured.decisions || [],
  action_items: structured.action_items || structured.actions || [],
  questions_raised: structured.questions_raised || [],
  keywords: structured.keywords || [],
  attendees: structured.attendees || [],
  notes: structured.notes || "",
});

export const buildHumanReadableMoM = (mom) => {
  let text = "";
  text += `📘 Overview:\n${mom.summary}\n\n`;
  text += `📅 Title: ${mom.title}\n`;
  text += `Date: ${new Date(mom.date).toLocaleDateString()}\n\n`;
  text += `📝 Summary:\n${mom.summary}\n\n`;

  if (mom.agenda.length) {
    text += "📋 Agenda:\n";
    mom.agenda.forEach((item, i) => (text += `${i + 1}. ${item}\n`));
    text += "\n";
  }
  if (mom.key_discussions.length) {
    text += "💬 Key Discussions:\n";
    mom.key_discussions.forEach((d, i) => (text += `${i + 1}. ${d}\n`));
    text += "\n";
  }
  if (mom.decisions.length) {
    text += "✅ Decisions:\n";
    mom.decisions.forEach((d, i) => (text += `${i + 1}. ${d}\n`));
    text += "\n";
  }
  if (mom.action_items.length) {
    text += "🎯 Action Items:\n";
    mom.action_items.forEach((a, i) => {
      const t =
        typeof a === "string"
          ? a
          : `${a.task || a.action || ""}${a.owner ? " — " + a.owner : ""}${
              a.due_date ? " (Due: " + a.due_date + ")" : ""
            }`;
      text += `${i + 1}. ${t}\n`;
    });
    text += "\n";
  }
  if (mom.attendees.length) {
    text += "👥 Attendees: " + mom.attendees.join(", ") + "\n\n";
  }
  if (mom.questions_raised.length) {
    text += "❓ Questions Raised:\n";
    mom.questions_raised.forEach((q, i) => (text += `${i + 1}. ${q}\n`));
    text += "\n";
  }
  if (mom.keywords.length) {
    text += "🏷 Keywords: " + mom.keywords.join(", ") + "\n\n";
  }
  if (mom.notes) {
    text += "🗒 Notes:\n" + mom.notes + "\n";
  }
  return text;
};

import mongoose from "mongoose";
import MembershipRequest from "../models/membershipRequestModel.js";
import Membership from "../models/membershipModel.js";
import Organization from "../models/organizationModel.js";
import userModel from "../models/userModel.js";
import AuditService from "./AuditService.js";
import {
  AppError,
  NotFoundError,
  ForbiddenError,
  ValidationError,
} from "../utils/errors.js";

class MembershipRequestService {
  /**
   * Validate MongoDB ObjectId
   */
  static _isValidObjectId(id) {
    return mongoose.Types.ObjectId.isValid(id);
  }

  /**
   * Create a new membership request
   */
  static async createRequest(userId, organizationId, message) {
    if (!organizationId) {
      throw new ValidationError("Organization ID is required.");
    }

    if (!this._isValidObjectId(organizationId)) {
      throw new ValidationError("Invalid organization ID.");
    }

    const cleanOrganizationId = new mongoose.Types.ObjectId(
      String(organizationId)
    );

    const organization = await Organization.findById(cleanOrganizationId);
    if (!organization) {
      throw new NotFoundError("Organization not found.");
    }

    // Check if user already has an active membership
    const existingMembership = await Membership.findOne({
      user: userId,
      organization: cleanOrganizationId,
      status: "active",
    }).lean();

    if (existingMembership) {
      throw new ValidationError("Already a member of this organization.");
    }

    // Check if there's already a pending request
    const existingRequest = await MembershipRequest.findOne({
      user: userId,
      organization: cleanOrganizationId,
      status: "pending",
    }).lean();

    if (existingRequest) {
      throw new AppError("Pending request already exists.", 409);
    }

    try {
      const membershipRequest = await MembershipRequest.create({
        user: userId,
        organization: cleanOrganizationId,
        message: message ? String(message).trim().substring(0, 500) : "",
        status: "pending",
      });
      return membershipRequest;
    } catch (error) {
      if (error.code === 11000) {
        throw new AppError("Duplicate request not allowed.", 409);
      }
      throw error;
    }
  }

  /**
   * Get membership requests for an organization
   */
  static async getOrganizationRequests(userId, organizationId, query) {
    const { status, search, page = 1, limit = 10, sortBy = "createdAt", sortOrder = "desc" } = query;

    if (!this._isValidObjectId(organizationId)) {
      throw new ValidationError("Invalid organization ID.");
    }
    const cleanOrganizationId = new mongoose.Types.ObjectId(String(organizationId));

    const allowedStatuses = ["pending", "approved", "rejected", "cancelled"];
    const validStatus = status && allowedStatuses.includes(status) ? status : null;
    if (status && !validStatus) {
      throw new ValidationError("Invalid status value.");
    }

    const organization = await Organization.findById(cleanOrganizationId);
    if (!organization) {
      throw new NotFoundError("Organization not found.");
    }

    // Check if user is admin or owner
    const membership = await Membership.findOne({
      user: userId,
      organization: cleanOrganizationId,
      role: "admin",
      status: "active",
    }).lean();

    const isOwner = organization.owner.toString() === userId.toString();
    if (!membership && !isOwner) {
      throw new ForbiddenError("Not authorized to view requests.");
    }

    const filter = { organization: { $eq: cleanOrganizationId } };
    if (validStatus) {
      filter.status = { $eq: validStatus };
    }

    const pageNum = parseInt(page, 10);
    const limitNum = parseInt(limit, 10);
    const skip = (pageNum - 1) * limitNum;

    const validSortFields = ["createdAt", "status", "name"];
    const sortField = validSortFields.includes(sortBy) ? sortBy : "createdAt";
    const sortDirection = sortOrder === "asc" ? 1 : -1;
    const sortObj = {};
    if (sortField === "name") {
      sortObj["user.name"] = sortDirection;
    } else {
      sortObj[sortField] = sortDirection;
    }

    const requests = await MembershipRequest.find(filter)
      .populate("user", "name email profilePic isAccountVerified")
      .sort(sortObj)
      .skip(skip)
      .limit(limitNum)
      .lean();

    let filteredRequests = requests;
    if (search && search.trim()) {
      const searchTerm = search.trim().toLowerCase();
      filteredRequests = requests.filter((req) => {
        const userName = req.user?.name?.toLowerCase() || "";
        const userEmail = req.user?.email?.toLowerCase() || "";
        const uId = req.user?._id?.toString() || "";
        return userName.includes(searchTerm) || userEmail.includes(searchTerm) || uId.includes(searchTerm);
      });
    }

    const total = await MembershipRequest.countDocuments(filter);
    const filteredTotal = search ? filteredRequests.length : total;

    return {
      requests: filteredRequests,
      pagination: {
        page: pageNum,
        limit: limitNum,
        total: filteredTotal,
        pages: Math.ceil(filteredTotal / limitNum),
      },
    };
  }

  /**
   * Get user's membership requests
   */
  static async getUserRequests(userId) {
    const requests = await MembershipRequest.find({ user: userId })
      .populate("organization", "name slug description logo")
      .sort({ createdAt: -1 })
      .lean();
    return requests;
  }

  /**
   * Approve a membership request
   */
  static async approveRequest(userId, requestId, reviewNotes) {
    if (!this._isValidObjectId(requestId)) {
      throw new ValidationError("Invalid membership request ID.");
    }
    const cleanRequestId = new mongoose.Types.ObjectId(String(requestId));

    const request = await MembershipRequest.findById(cleanRequestId).populate("organization");
    if (!request) {
      throw new NotFoundError("Membership request not found.");
    }
    if (request.status !== "pending") {
      throw new ValidationError("Request is not in pending status.");
    }

    const membership = await Membership.findOne({
      user: userId,
      organization: request.organization._id,
      role: "admin",
      status: "active",
    }).lean();
    const isOwner = request.organization.owner.toString() === userId.toString();
    if (!membership && !isOwner) {
      throw new ForbiddenError("Not authorized to approve requests.");
    }

    const session = await mongoose.startSession();
    session.startTransaction();
    let newMembership;
    
    try {
      request.status = "approved";
      request.reviewedBy = userId;
      request.reviewedAt = new Date();
      request.reviewNotes = reviewNotes ? String(reviewNotes).trim().substring(0, 500) : "";
      await request.save({ session });

      [newMembership] = await Membership.create([{
        user: request.user,
        organization: request.organization._id,
        role: "member",
        status: "active",
      }], { session });

      await userModel.findByIdAndUpdate(request.user, {
        role: "member",
        organization: request.organization._id,
        hasCompletedOnboarding: true,
      }, { session });

      await session.commitTransaction();
    } catch (error) {
      await session.abortTransaction();
      throw error;
    } finally {
      session.endSession();
    }

    AuditService.logAction({
      actorId: userId,
      action: "MEMBERSHIP_REQUEST_APPROVED",
      entity: "MembershipRequest",
      entityId: request._id,
      organizationId: request.organization._id,
      details: { userId: request.user },
    });

    return { request, membership: newMembership };
  }

  /**
   * Reject a membership request
   */
  static async rejectRequest(userId, requestId, reviewNotes) {
    if (!this._isValidObjectId(requestId)) {
      throw new ValidationError("Invalid membership request ID.");
    }
    const cleanRequestId = new mongoose.Types.ObjectId(String(requestId));

    const request = await MembershipRequest.findById(cleanRequestId).populate("organization");
    if (!request) {
      throw new NotFoundError("Membership request not found.");
    }
    if (request.status !== "pending") {
      throw new ValidationError("Request is not in pending status.");
    }

    const membership = await Membership.findOne({
      user: userId,
      organization: request.organization._id,
      role: "admin",
      status: "active",
    }).lean();
    const isOwner = request.organization.owner.toString() === userId.toString();
    if (!membership && !isOwner) {
      throw new ForbiddenError("Not authorized to reject requests.");
    }

    request.status = "rejected";
    request.reviewedBy = userId;
    request.reviewedAt = new Date();
    request.reviewNotes = reviewNotes ? String(reviewNotes).trim().substring(0, 500) : "";
    await request.save();

    AuditService.logAction({
      actorId: userId,
      action: "MEMBERSHIP_REQUEST_REJECTED",
      entity: "MembershipRequest",
      entityId: request._id,
      organizationId: request.organization._id,
      details: { userId: request.user, reviewNotes },
    });

    return { request };
  }

  /**
   * Cancel a membership request
   */
  static async cancelRequest(userId, requestId) {
    if (!this._isValidObjectId(requestId)) {
      throw new ValidationError("Invalid membership request ID.");
    }
    const cleanRequestId = new mongoose.Types.ObjectId(String(requestId));

    const request = await MembershipRequest.findById(cleanRequestId);
    if (!request) {
      throw new NotFoundError("Membership request not found.");
    }

    if (request.user.toString() !== userId.toString()) {
      throw new ForbiddenError("Not authorized to cancel this request.");
    }

    if (request.status !== "pending") {
      throw new ValidationError("Can only cancel pending requests.");
    }

    request.status = "cancelled";
    await request.save();

    return { request };
  }

  /**
   * Bulk approve membership requests
   */
  static async bulkApproveRequests(userId, requestIds, reviewNotes) {
    if (!Array.isArray(requestIds) || requestIds.length === 0) {
      throw new ValidationError("Request IDs array is required.");
    }

    const validRequestIds = requestIds
      .filter((id) => this._isValidObjectId(id))
      .map((id) => new mongoose.Types.ObjectId(String(id)));

    if (validRequestIds.length === 0) {
      throw new ValidationError("No valid request IDs provided.");
    }

    const requests = await MembershipRequest.find({
      _id: { $in: validRequestIds },
    }).populate("organization");

    if (requests.length === 0) {
      throw new NotFoundError("No membership requests found.");
    }

    const results = [];
    const errors = [];

    // Run each in its own transaction (or without if we can't batch easily, but we'll use transaction inside the loop or just process one by one)
    for (const request of requests) {
      if (request.status !== "pending") {
        errors.push({ requestId: request._id, message: "Request is not in pending status." });
        continue;
      }

      const membership = await Membership.findOne({
        user: userId,
        organization: request.organization._id,
        role: "admin",
        status: "active",
      }).lean();
      const isOwner = request.organization.owner.toString() === userId.toString();
      
      if (!membership && !isOwner) {
        errors.push({ requestId: request._id, message: "Not authorized to approve this request." });
        continue;
      }

      const session = await mongoose.startSession();
      session.startTransaction();
      let newMembership;
      try {
        request.status = "approved";
        request.reviewedBy = userId;
        request.reviewedAt = new Date();
        request.reviewNotes = reviewNotes ? String(reviewNotes).trim().substring(0, 500) : "";
        await request.save({ session });

        [newMembership] = await Membership.create([{
          user: request.user,
          organization: request.organization._id,
          role: "member",
          status: "active",
        }], { session });

        await userModel.findByIdAndUpdate(request.user, {
          role: "member",
          organization: request.organization._id,
          hasCompletedOnboarding: true,
        }, { session });

        await session.commitTransaction();

        AuditService.logAction({
          actorId: userId,
          action: "MEMBERSHIP_REQUEST_APPROVED",
          entity: "MembershipRequest",
          entityId: request._id,
          organizationId: request.organization._id,
          details: { userId: request.user },
        });

        results.push({ requestId: request._id, membershipId: newMembership._id, status: "approved" });
      } catch (error) {
        await session.abortTransaction();
        errors.push({ requestId: request._id, message: "Internal server error during approval." });
      } finally {
        session.endSession();
      }
    }

    return { results, errors };
  }

  /**
   * Bulk reject membership requests
   */
  static async bulkRejectRequests(userId, requestIds, reviewNotes) {
    if (!Array.isArray(requestIds) || requestIds.length === 0) {
      throw new ValidationError("Request IDs array is required.");
    }

    const validRequestIds = requestIds
      .filter((id) => this._isValidObjectId(id))
      .map((id) => new mongoose.Types.ObjectId(String(id)));

    if (validRequestIds.length === 0) {
      throw new ValidationError("No valid request IDs provided.");
    }

    const requests = await MembershipRequest.find({
      _id: { $in: validRequestIds },
    }).populate("organization");

    if (requests.length === 0) {
      throw new NotFoundError("No membership requests found.");
    }

    const results = [];
    const errors = [];

    for (const request of requests) {
      if (request.status !== "pending") {
        errors.push({ requestId: request._id, message: "Request is not in pending status." });
        continue;
      }

      const membership = await Membership.findOne({
        user: userId,
        organization: request.organization._id,
        role: "admin",
        status: "active",
      }).lean();
      const isOwner = request.organization.owner.toString() === userId.toString();
      
      if (!membership && !isOwner) {
        errors.push({ requestId: request._id, message: "Not authorized to reject this request." });
        continue;
      }

      request.status = "rejected";
      request.reviewedBy = userId;
      request.reviewedAt = new Date();
      request.reviewNotes = reviewNotes ? String(reviewNotes).trim().substring(0, 500) : "";
      await request.save();

      AuditService.logAction({
        actorId: userId,
        action: "MEMBERSHIP_REQUEST_REJECTED",
        entity: "MembershipRequest",
        entityId: request._id,
        organizationId: request.organization._id,
        details: { userId: request.user, reviewNotes },
      });

      results.push({ requestId: request._id, status: "rejected" });
    }

    return { results, errors };
  }
}

