import crypto from "crypto";
import { google } from "googleapis";
import axios from "axios";
import cron from "node-cron";
import CalendarIntegration from "../models/calendarIntegrationModel.js";
import Meeting from "../models/meetingModel.js";

// Encryption setup
const ALGORITHM = "aes-256-gcm";
const ENCRYPTION_KEY =
  process.env.TOKEN_ENCRYPTION_KEY || "12345678901234567890123456789012"; // 32 bytes

const encrypt = (text) => {
  if (!text) return text;
  const iv = crypto.randomBytes(16);
  const cipher = crypto.createCipheriv(
    ALGORITHM,
    Buffer.from(ENCRYPTION_KEY),
    iv,
  );
  let encrypted = cipher.update(text, "utf8", "hex");
  encrypted += cipher.final("hex");
  const authTag = cipher.getAuthTag().toString("hex");
  return `${iv.toString("hex")}:${encrypted}:${authTag}`;
};

const decrypt = (encryptedData) => {
  if (!encryptedData) return encryptedData;
  const parts = encryptedData.split(":");
  if (parts.length !== 3) return encryptedData; // not encrypted or wrong format
  const [ivHex, encryptedText, authTagHex] = parts;
  const decipher = crypto.createDecipheriv(
    ALGORITHM,
    Buffer.from(ENCRYPTION_KEY),
    Buffer.from(ivHex, "hex"),
  );
  decipher.setAuthTag(Buffer.from(authTagHex, "hex"));
  let decrypted = decipher.update(encryptedText, "hex", "utf8");
  decrypted += decipher.final("utf8");
  return decrypted;
};

// Google OAuth client
export const getGoogleOAuthClient = () => {
  return new google.auth.OAuth2(
    process.env.GOOGLE_CLIENT_ID,
    process.env.GOOGLE_CLIENT_SECRET,
    process.env.GOOGLE_REDIRECT_URI ||
      "http://localhost:4000/api/calendar/google/callback",
  );
};

// --- Calendar Sync Operations ---

const getGoogleCalendarClient = (accessToken, refreshToken) => {
  const oAuth2Client = getGoogleOAuthClient();
  oAuth2Client.setCredentials({
    access_token: accessToken,
    refresh_token: refreshToken,
  });
  return google.calendar({ version: "v3", auth: oAuth2Client });
};

export const syncMeetingToGoogle = async (integration, meeting) => {
  try {
    const accessToken = decrypt(integration.accessToken);
    const refreshToken = decrypt(integration.refreshToken);
    const calendar = getGoogleCalendarClient(accessToken, refreshToken);

    const event = {
      summary: meeting.title,
      description: meeting.description || "",
      start: {
        dateTime: meeting.date.toISOString(),
        timeZone: "UTC", // Simplify
      },
      end: {
        dateTime: new Date(
          meeting.date.getTime() + (meeting.duration || 60) * 60000,
        ).toISOString(),
        timeZone: "UTC",
      },
      location: meeting.venue || meeting.location || "",
    };

    const existingRef = meeting.externalCalendarRefs.find(
      (r) => r.provider === "google",
    );
    if (existingRef) {
      await calendar.events.update({
        calendarId: integration.externalCalendarId || "primary",
        eventId: existingRef.eventId,
        requestBody: event,
      });
      return { provider: "google", eventId: existingRef.eventId };
    } else {
      const res = await calendar.events.insert({
        calendarId: integration.externalCalendarId || "primary",
        requestBody: event,
      });
      return { provider: "google", eventId: res.data.id };
    }
  } catch (err) {
    console.error("Google sync error:", err.message);
    throw err;
  }
};

export const deleteGoogleMeeting = async (integration, eventId) => {
  try {
    const accessToken = decrypt(integration.accessToken);
    const refreshToken = decrypt(integration.refreshToken);
    const calendar = getGoogleCalendarClient(accessToken, refreshToken);
    await calendar.events.delete({
      calendarId: integration.externalCalendarId || "primary",
      eventId,
    });
  } catch (err) {
    console.error("Google delete error:", err.message);
  }
};

export const syncMeetingToOutlook = async (integration, meeting) => {
  try {
    const accessToken = decrypt(integration.accessToken);
    const event = {
      subject: meeting.title,
      body: { contentType: "Text", content: meeting.description || "" },
      start: { dateTime: meeting.date.toISOString(), timeZone: "UTC" },
      end: {
        dateTime: new Date(
          meeting.date.getTime() + (meeting.duration || 60) * 60000,
        ).toISOString(),
        timeZone: "UTC",
      },
      location: { displayName: meeting.venue || meeting.location || "" },
    };

    const existingRef = meeting.externalCalendarRefs.find(
      (r) => r.provider === "outlook",
    );
    let res;
    if (existingRef) {
      res = await axios.patch(
        `https://graph.microsoft.com/v1.0/me/events/${existingRef.eventId}`,
        event,
        { headers: { Authorization: `Bearer ${accessToken}` } },
      );
      return { provider: "outlook", eventId: existingRef.eventId };
    } else {
      res = await axios.post(
        "https://graph.microsoft.com/v1.0/me/events",
        event,
        {
          headers: { Authorization: `Bearer ${accessToken}` },
        },
      );
      return { provider: "outlook", eventId: res.data.id };
    }
  } catch (err) {
    console.error("Outlook sync error:", err.message);
    throw err;
  }
};

export const deleteOutlookMeeting = async (integration, eventId) => {
  try {
    const accessToken = decrypt(integration.accessToken);
    await axios.delete(
      `https://graph.microsoft.com/v1.0/me/events/${eventId}`,
      {
        headers: { Authorization: `Bearer ${accessToken}` },
      },
    );
  } catch (err) {
    console.error("Outlook delete error:", err.message);
  }
};

export const pushMeetingToIntegrations = async (userId, meeting) => {
  const integrations = await CalendarIntegration.find({
    userId,
    syncEnabled: true,
  });
  const newRefs = [];
  for (const integration of integrations) {
    try {
      if (integration.provider === "google") {
        const ref = await syncMeetingToGoogle(integration, meeting);
        if (ref) newRefs.push(ref);
      } else if (integration.provider === "outlook") {
        const ref = await syncMeetingToOutlook(integration, meeting);
        if (ref) newRefs.push(ref);
      }
      integration.lastSyncedAt = new Date();
      await integration.save();
    } catch (err) {
      console.error(`Failed to push to ${integration.provider}`);
    }
  }

  if (newRefs.length > 0) {
    const combinedRefs = [...meeting.externalCalendarRefs];
    newRefs.forEach((nr) => {
      if (!combinedRefs.find((r) => r.provider === nr.provider)) {
        combinedRefs.push(nr);
      }
    });
    meeting.externalCalendarRefs = combinedRefs;
    await meeting.save();
  }
};

export const deleteMeetingFromIntegrations = async (
  userId,
  externalCalendarRefs,
) => {
  if (!externalCalendarRefs || externalCalendarRefs.length === 0) return;
  const integrations = await CalendarIntegration.find({
    userId,
    syncEnabled: true,
  });

  for (const integration of integrations) {
    const ref = externalCalendarRefs.find(
      (r) => r.provider === integration.provider,
    );
    if (ref) {
      if (integration.provider === "google") {
        await deleteGoogleMeeting(integration, ref.eventId);
      } else if (integration.provider === "outlook") {
        await deleteOutlookMeeting(integration, ref.eventId);
      }
    }
  }
};

// --- Refresh tokens & Cron ---

const refreshGoogleToken = async (integration) => {
  try {
    const oauth2Client = getGoogleOAuthClient();
    oauth2Client.setCredentials({
      refresh_token: decrypt(integration.refreshToken),
    });
    const { credentials } = await oauth2Client.refreshAccessToken();
    integration.accessToken = encrypt(credentials.access_token);
    integration.expiresAt = new Date(credentials.expiry_date);
    await integration.save();
  } catch (err) {
    console.error("Failed to refresh Google token", err.message);
    integration.syncEnabled = false;
    await integration.save();
  }
};

const refreshOutlookToken = async (integration) => {
  try {
    const params = new URLSearchParams({
      client_id: process.env.MS_CLIENT_ID,
      client_secret: process.env.MS_CLIENT_SECRET,
      grant_type: "refresh_token",
      refresh_token: decrypt(integration.refreshToken),
    });
    const res = await axios.post(
      `https://login.microsoftonline.com/${process.env.MS_TENANT_ID || "common"}/oauth2/v2.0/token`,
      params,
    );
    integration.accessToken = encrypt(res.data.access_token);
    if (res.data.refresh_token) {
      integration.refreshToken = encrypt(res.data.refresh_token);
    }
    integration.expiresAt = new Date(Date.now() + res.data.expires_in * 1000);
    await integration.save();
  } catch (err) {
    console.error("Failed to refresh Outlook token", err.message);
    integration.syncEnabled = false;
    await integration.save();
  }
};

// Cron job to run every 15 minutes to refresh expiring tokens
export const initCalendarSyncCron = () => {
  cron.schedule("*/15 * * * *", async () => {
    console.log("Running Calendar Sync Reconciliation Cron");
    const expiringTime = new Date(Date.now() + 30 * 60 * 1000); // 30 minutes
    const integrations = await CalendarIntegration.find({
      syncEnabled: true,
      expiresAt: { $lte: expiringTime },
    });

    for (const integration of integrations) {
      if (integration.provider === "google" && integration.refreshToken) {
        await refreshGoogleToken(integration);
      } else if (
        integration.provider === "outlook" &&
        integration.refreshToken
      ) {
        await refreshOutlookToken(integration);
      }
    }
  });
};

export { encrypt, decrypt };

/**
 * importanceScoringService.js
 *
 * Applies the pure scoring logic in utils/importanceScoring.js to actual
 * Decision / ActionItem documents: persisting scores, tracking access, and
 * recording user feedback so the score stays up to date as usage evolves.
 */

import Decision from "../models/decisionModel.js";
import ActionItem from "../models/actionItemModel.js";
import { computeImportanceScore } from "../utils/importanceScoring.js";

const MODELS = {
  decision: Decision,
  actionItem: ActionItem,
};

function resolveModel(type) {
  const Model = MODELS[type];
  if (!Model) {
    throw new Error(`Unknown memory type: ${type}`);
  }
  return Model;
}

/**
 * Recomputes and persists the importance score for a single already-loaded
 * document (does not re-fetch from the DB). Returns the updated document.
 */
export async function applyImportanceScore(document, now = new Date()) {
  const { score, factors } = computeImportanceScore(document, now);
  document.importanceScore = score;
  document.importanceFactors = factors;
  document.importanceUpdatedAt = now;
  await document.save();
  return document;
}

/**
 * Recomputes and persists the importance score for a memory by id.
 */
export async function recalculateImportanceById(type, id) {
  const Model = resolveModel(type);
  const document = await Model.findById(id);
  if (!document) return null;
  return applyImportanceScore(document);
}

/**
 * Batch recalculates importance scores for every memory of the given type
 * (optionally scoped to an organization). Used by the maintenance endpoint
 * and can also be run as a scheduled job.
 *
 * Runs in small batches so it stays reasonable on large collections while
 * remaining simple (no external job queue dependency).
 */
export async function recalculateAllImportanceScores({
  organization = undefined,
  batchSize = 200,
} = {}) {
  const filter = organization === undefined ? {} : { organization };
  const results = { decisions: 0, actionItems: 0 };

  for (const [key, Model] of Object.entries(MODELS)) {
    let skip = 0;
    // eslint-disable-next-line no-constant-condition
    while (true) {
      const batch = await Model.find(filter).skip(skip).limit(batchSize);
      if (batch.length === 0) break;

      const now = new Date();
      await Promise.all(batch.map((doc) => applyImportanceScore(doc, now)));

      if (key === "decision") results.decisions += batch.length;
      else results.actionItems += batch.length;

      if (batch.length < batchSize) break;
      skip += batchSize;
    }
  }

  return results;
}

/**
 * Records that a memory was retrieved/opened by a user: bumps the access
 * counter, updates lastAccessedAt, and recalculates its importance score.
 * Fails silently (logs only) so access tracking never breaks a read path.
 */
export async function recordMemoryAccess(type, id) {
  try {
    const Model = resolveModel(type);
    const document = await Model.findById(id);
    if (!document) return null;

    document.accessCount = (document.accessCount || 0) + 1;
    document.lastAccessedAt = new Date();

    return await applyImportanceScore(document);
  } catch (error) {
    console.error(`recordMemoryAccess error (${type}:${id}):`, error);
    return null;
  }
}

/**
 * Records a batch of accesses (e.g. every item in a list response) without
 * awaiting each one sequentially. Intended to be fire-and-forget from the
 * controller so it never slows down the response.
 */
export function recordMemoryAccessBatch(type, ids = []) {
  return Promise.all(ids.map((id) => recordMemoryAccess(type, id))).catch(
    (error) => {
      console.error(`recordMemoryAccessBatch error (${type}):`, error);
    },
  );
}

/**
 * Records explicit user feedback (1-5 rating) on a memory and recalculates
 * its importance score to reflect the new average.
 */
export async function recordMemoryFeedback(type, id, rating) {
  const numericRating = Number(rating);
  if (
    !Number.isFinite(numericRating) ||
    numericRating < 1 ||
    numericRating > 5
  ) {
    throw new Error("Feedback rating must be a number between 1 and 5");
  }

  const Model = resolveModel(type);
  const document = await Model.findById(id);
  if (!document) return null;

  document.feedbackScore = (document.feedbackScore || 0) + numericRating;
  document.feedbackCount = (document.feedbackCount || 0) + 1;

  return applyImportanceScore(document);
}

export default {
  applyImportanceScore,
  recalculateImportanceById,
  recalculateAllImportanceScores,
  recordMemoryAccess,
  recordMemoryAccessBatch,
  recordMemoryFeedback,
};

import { Queue, Worker } from "bullmq";
import Redis from "ioredis";
import crypto from "crypto";
import axios from "axios";
import Webhook from "../models/Webhook.js";
import WebhookDelivery from "../models/WebhookDelivery.js";
import eventBus from "./eventBus.js";

// Redis connection management
let _producerConnection = null;
let _workerConnection = null;
let _webhookQueueInstance = null;

function getProducerConnection() {
  if (!process.env.REDIS_URI) return null;
  if (!_producerConnection) {
    _producerConnection = new Redis(process.env.REDIS_URI, {
      maxRetriesPerRequest: 3, // Fail fast for requests adding tasks to queue
      family: 0,
    });
    _producerConnection.on("error", (err) => {
      console.error("⚠️ Webhook Producer Redis Connection Error:", err.message);
    });
  }
  return _producerConnection;
}

function getWorkerConnection() {
  if (!process.env.REDIS_URI) return null;
  if (!_workerConnection) {
    _workerConnection = new Redis(process.env.REDIS_URI, {
      maxRetriesPerRequest: null, // Unlimited retries for background workers
      family: 0,
    });
    _workerConnection.on("error", (err) => {
      console.error("⚠️ Webhook Worker Redis Connection Error:", err.message);
    });
  }
  return _workerConnection;
}

function getWebhookQueue() {
  if (!process.env.REDIS_URI) return null;
  if (!_webhookQueueInstance) {
    const conn = getProducerConnection();
    if (conn) {
      _webhookQueueInstance = new Queue("webhook-dispatches", {
        connection: conn,
      });
    }
  }
  return _webhookQueueInstance;
}

export const webhookQueue = {
  add: async (...args) => {
    const q = getWebhookQueue();
    if (!q) {
      console.warn("⚠️ Queue operation ignored: Redis is not configured.");
      return null;
    }
    return await q.add(...args);
  },
  get isActive() {
    return getWebhookQueue() !== null;
  },
};

/**
 * Signs the payload using HMAC SHA-256 with the webhook's secret and a timestamp.
 * Provides replay protection for downstream consumers.
 * @param {object|string} payload - Webhook payload object
 * @param {string} timestamp - ISO timestamp
 * @param {string} secret - Webhook secret key
 * @returns {string} Hex signature
 */
export const generateSignature = (payload, timestamp, secret) => {
  const content = `${timestamp}.${typeof payload === "string" ? payload : JSON.stringify(payload)}`;
  return crypto.createHmac("sha256", secret).update(content).digest("hex");
};

/**
 * Core dispatch function. Sends signed POST request to client url and logs delivery status.
 * @param {string} webhookId - MongoDB Webhook Subscription ID
 * @param {object} payload - Payload object containing event details
 * @param {object} [options] - Additional dispatch options (attempt count, isFinalAttempt)
 * @returns {Promise<object>} Created WebhookDelivery record
 */
export const performDispatch = async (webhookId, payload, options = {}) => {
  const attempt = options.attempt || 1;
  const isFinalAttempt = options.isFinalAttempt || false;

  const webhook = await Webhook.findById(webhookId).select("+secret");
  if (!webhook || !webhook.isActive) {
    console.log(
      `⚠️ Webhook subscription ${webhookId} not found or inactive. Skipping.`,
    );
    return null;
  }

  const timestamp = new Date().toISOString();
  const signature = generateSignature(payload, timestamp, webhook.secret);
  const startTime = Date.now();

  try {
    console.log(
      `📡 Sending webhook event '${payload.event}' to ${webhook.targetUrl} (Attempt ${attempt})...`,
    );

    const response = await axios.post(webhook.targetUrl, payload, {
      headers: {
        "Content-Type": "application/json",
        "x-meetonmemory-signature": signature,
        "x-meetonmemory-request-timestamp": timestamp,
      },
      timeout: 10000, // 10 second timeout
    });

    const sanitizeHeaders = (headers) => {
      if (!headers || typeof headers !== "object") return null;
      const sanitized = { ...headers };
      delete sanitized["set-cookie"];
      delete sanitized["authorization"];
      delete sanitized["cookie"];
      delete sanitized["x-auth-token"];
      return sanitized;
    };

    const executionTimeMs = Date.now() - startTime;

    // Log successful delivery attempt
    const delivery = await WebhookDelivery.create({
      webhookId: webhook._id,
      organizationId: webhook.organizationId,
      event: payload.event || "custom",
      payload,
      responseStatus: response.status,
      responseHeaders: sanitizeHeaders(response.headers),
      responseBody:
        typeof response.data === "string"
          ? response.data.slice(0, 2000)
          : JSON.stringify(response.data || {}).slice(0, 2000),
      executionTimeMs,
      attempt,
      status: "success",
    });

    // Reset failure counts and update health status
    await Webhook.findByIdAndUpdate(webhookId, {
      consecutiveFailures: 0,
      healthStatus: "healthy",
      lastDeliveredAt: new Date(),
    });

    console.log(
      `✅ Webhook event '${payload.event}' successfully sent to ${webhook.targetUrl}. Status: ${response.status}`,
    );

    return delivery;
  } catch (error) {
    const executionTimeMs = Date.now() - startTime;
    const responseStatus = error.response ? error.response.status : null;
    const responseHeaders = error.response
      ? { ...error.response.headers }
      : null;
    if (responseHeaders) {
      delete responseHeaders["set-cookie"];
      delete responseHeaders["authorization"];
      delete responseHeaders["cookie"];
      delete responseHeaders["x-auth-token"];
    }

    const responseBody = error.response?.data
      ? typeof error.response.data === "string"
        ? error.response.data.slice(0, 2000)
        : JSON.stringify(error.response.data).slice(0, 2000)
      : null;

    const errorMsg = responseStatus
      ? `HTTP Status ${responseStatus}`
      : error.message;
    const deliveryStatus = isFinalAttempt ? "dlq" : "failed";

    // Create failed/dlq delivery record
    const delivery = await WebhookDelivery.create({
      webhookId: webhook._id,
      organizationId: webhook.organizationId,
      event: payload.event || "custom",
      payload,
      responseStatus,
      responseHeaders,
      responseBody,
      executionTimeMs,
      attempt,
      status: deliveryStatus,
      errorReason: errorMsg,
    });

    // Atomically increment consecutive failures to prevent race conditions across concurrent workers
    const updatedWebhook = await Webhook.findByIdAndUpdate(
      webhookId,
      { $inc: { consecutiveFailures: 1 } },
      { new: true },
    );

    if (updatedWebhook) {
      const newFailures = updatedWebhook.consecutiveFailures;
      let newHealthStatus = updatedWebhook.healthStatus;
      let newIsActive = updatedWebhook.isActive;

      if (newFailures >= 15) {
        newHealthStatus = "paused";
        newIsActive = false;
        console.warn(
          `🚨 Webhook ${updatedWebhook._id} (${updatedWebhook.targetUrl}) reached 15 consecutive failures. Auto-pausing subscription.`,
        );
      } else if (newFailures >= 10) {
        newHealthStatus = "degraded";
        console.warn(
          `⚠️ Webhook ${updatedWebhook._id} (${updatedWebhook.targetUrl}) health degraded (${newFailures} consecutive failures).`,
        );
      }

      if (
        newHealthStatus !== updatedWebhook.healthStatus ||
        newIsActive !== updatedWebhook.isActive
      ) {
        await Webhook.findByIdAndUpdate(webhookId, {
          healthStatus: newHealthStatus,
          isActive: newIsActive,
        });
      }
    }

    console.error(
      `❌ Webhook dispatch failed for ${webhook.targetUrl} (Attempt ${attempt}): ${errorMsg}`,
    );

    if (deliveryStatus === "dlq") {
      console.error(
        `☠️ Webhook dispatch payload moved to Dead-Letter Queue (DLQ) after ${attempt} attempts.`,
      );
    }

    // Throwing error allows BullMQ to retry if not in final attempt
    throw new Error(`Webhook dispatch failed: ${errorMsg}`);
  }
};

/**
 * Redelivers a specific past webhook delivery payload manually.
 * @param {string} deliveryId - MongoDB WebhookDelivery ID
 * @returns {Promise<object>} New WebhookDelivery audit record
 */
export const redeliverWebhookDelivery = async (deliveryId) => {
  const originalDelivery = await WebhookDelivery.findById(deliveryId);
  if (!originalDelivery) {
    throw new Error("Webhook delivery record not found.");
  }

  return await performDispatch(
    originalDelivery.webhookId,
    originalDelivery.payload,
    {
      attempt: originalDelivery.attempt + 1,
      isFinalAttempt: false,
    },
  );
};

/**
 * Dispatches the event payload to all active webhooks subscribed to this event in the organization.
 * @param {string} organizationId - Target organization ID
 * @param {string} event - Event name (e.g. 'meeting.created')
 * @param {object} data - Event data payload
 */
export const dispatchWebhookEvent = async (organizationId, event, data) => {
  if (!organizationId) {
    return;
  }

  try {
    // Find active webhooks for this organization that subscribe to this specific event
    const webhooks = await Webhook.find({
      organizationId,
      events: event,
      isActive: true,
    });

    if (webhooks.length === 0) {
      return;
    }

    const payload = {
      event,
      timestamp: new Date().toISOString(),
      data,
    };

    for (const webhook of webhooks) {
      if (getWebhookQueue()) {
        // Add to BullMQ with exponential backoff retries for reliability
        await webhookQueue.add(
          "dispatch-webhook",
          { webhookId: webhook._id, payload },
          {
            attempts: 5,
            backoff: {
              type: "exponential",
              delay: 2000, // 2s initial delay
            },
          },
        );
      } else {
        // Fallback: Synchronous dispatch in local/dev environment without Redis
        performDispatch(webhook._id, payload, {
          attempt: 1,
          isFinalAttempt: true,
        }).catch((err) => {
          console.error(
            "⚠️ Local webhook dispatch sync fallback failed:",
            err.message,
          );
        });
      }
    }
  } catch (err) {
    console.error("⚠️ Failed to queue webhook dispatches:", err.message);
  }
};

/**
 * Initializes the Webhook worker listening on the dispatch queue.
 */
export const initWebhookWorker = () => {
  const connection = getWorkerConnection();
  if (!connection) {
    console.warn(
      "⚠️ Redis not configured. Webhook background worker will not start (falling back to sync dispatch).",
    );
    return;
  }

  const worker = new Worker(
    "webhook-dispatches",
    async (job) => {
      const { webhookId, payload } = job.data;
      const attempt = job.attemptsMade + 1;
      const maxAttempts = job.opts?.attempts || 5;
      const isFinalAttempt = attempt >= maxAttempts;

      await performDispatch(webhookId, payload, { attempt, isFinalAttempt });
    },
    { connection, concurrency: 10 },
  );

  worker.on("completed", (job) => {
    console.log(`✅ Webhook job ${job.id} completed successfully`);
  });

  worker.on("failed", (job, err) => {
    console.error(
      `❌ Webhook job ${job.id} failed attempt ${job.attemptsMade}:`,
      err.message,
    );
  });

  worker.on("error", (err) => {
    console.error("❌ Webhook Worker error:", err.message);
  });

  console.log(
    "✅ Webhook Worker initialized and listening to webhook-dispatches queue",
  );
};

// ─────────────────────────────────────────────────────────────
// 📡 Register internal event bus listeners to fire webhooks
// ─────────────────────────────────────────────────────────────

eventBus.on("meeting.created", (meeting) => {
  const orgId = meeting?.organization;
  if (!orgId) return;

  const data = {
    meetingId: meeting._id,
    title: meeting.title,
    description: meeting.description,
    date: meeting.date,
    meetingType: meeting.meetingType,
    organizationId: orgId,
  };

  dispatchWebhookEvent(orgId, "meeting.created", data);
});

eventBus.on("mom.generated", (meeting) => {
  const orgId = meeting?.organization;
  if (!orgId) return;

  const data = {
    meetingId: meeting._id,
    title: meeting.title,
    summary: meeting.summary,
    structuredMoM: meeting.structuredMoM,
    organizationId: orgId,
  };

  dispatchWebhookEvent(orgId, "mom.generated", data);
});

eventBus.on("policy.updated", (policy) => {
  const orgId = policy.organization;
  if (!orgId) return;

  const data = {
    policyId: policy._id,
    name: policy.name,
    version: policy.version,
    summary: policy.summary,
    key_changes: policy.key_changes,
    keywords: policy.keywords,
    organizationId: orgId,
  };

  dispatchWebhookEvent(orgId, "policy.updated", data);
});

